{
    "level": "A2–B1",
    "intro": "In this topic you will learn <strong>word order</strong> with auxiliary, modal and phrasal verbs: sentence structure and rules for placing adjuncts.",
    "rules": [
        {
            "label": "Auxiliaries",
            "color": "emerald",
            "text": "<strong>Subject + Auxiliary + Main Verb + Object: ",
            "example": "She is reading a book. <strong>required</strong> between the verb and the particle:"
        },
        {
            "label": "Модальні",
            "color": "blue",
            "text": "<strong>Subject + Modal + Base Verb + Object</strong> (без to):",
            "example": "He can speak English."
        },
        {
            "label": "Phrasal Verbs",
            "color": "amber",
            "text": "Займенник <strong>обовʼязково</strong> між дієсловом і часткою:",
            "example": "Turn it off. (NOT: Turn off it.)"
        }
    ]
}

{
    "title": "1. Auxiliary Verbs",
    "intro": "Auxiliary verbs be, do, have stand before the main verb:",
    "items": [
        {
            "label": "Be",
            "title": "Continuous / Passive",
            "subtitle": "She is reading. / The book was written."
        },
        {
            "label": "Have",
            "title": "Perfect tenses",
            "subtitle": "They have finished. / He had left."
        },
        {
            "label": "Do",
            "title": "Questions / Negatives",
            "subtitle": "Do you know? / She doesn't like it."
        }
    ]
}

{
    "title": "2. Modal Verbs",
    "sections": [
        {
            "label": "Structure with modals",
            "color": "emerald",
            "description": "Modal verbs <strong>can, should, must, might, will, would</strong> stand before the main verb (without to).",
            "examples": [
                {
                    "en": "She can speak English.",
                    "ua": "She can speak in English."
                },
                {
                    "en": "You should finish your homework.",
                    "ua": "You should finish your homework."
                },
                {
                    "en": "He must call the doctor.",
                    "ua": "He must call the doctor."
                },
                {
                    "en": "They might arrive late.",
                    "ua": "They might be late."
                }
            ]
        },
        {
            "label": "Objection with modals",
            "color": "sky",
            "description": "In negatives, <strong>not</strong> is placed after the modal verb.",
            "examples": [
                {
                    "en": "She cannot (can't) swim.",
                    "ua": "She does not know how to swim."
                },
                {
                    "en": "You should not (shouldn't) eat too much.",
                    "ua": " eat too much."
                },
                {
                    "en": "He must not (mustn't) be late.",
                    "ua": "He must not be late."
                }
            ],
            "note": "The modal verb is always followed by a base form (without to, without -s)."
        }
    ]
}

{
    "title": "3. Phrasal verbs - separable (Separable)",
    "sections": [
        {
            "label": "Noun suffix",
            "color": "emerald",
            "description": "Noun suffix can stand <strong>between</strong> the verb and the particle or <strong>after</strong> the whole construction.",
            "examples": [
                {
                    "en": "Turn off the light. = Turn the light off.",
                    "ua": "Turn off the light."
                },
                {
                    "en": "Pick up the package. = Pick the package up.",
                    "ua": "Take the package."
                },
                {
                    "en": "Put on your coat. = Put ​​your coat on.[[[CODX_SEG_22]. ❌ Turn off it.",
                    "ua": "Надягни пальто."
                }
            ]
        },
        {
            "label": "Додаток-займенник",
            "color": "rose",
            "description": "Займенник (it, him, her, them) <strong>ОБОВ'ЯЗКОВО</strong> стоїть між дієсловом і часткою.",
            "examples": [
                {
                    "en": "Turn it off. ❌ Turn off it.",
                    "ua": "Turn off it."
                },
                {
                    "en": "Pick them up. ❌ Pick up them.",
                    "ua": "Pick it up."
                },
                {
                    "en": "Put it on. ❌ Put on it.",
                    "ua": "Put it on."
                }
            ],
            "note": "This rule is mandatory! A pronoun never follows a particle."
        }
    ]
}

{
    "title": "4. Phrasal verbs - inseparable (Inseparable)",
    "sections": [
        {
            "label": "Appendix after phrasal verb",
            "color": "emerald",
            "description": "In <strong>inseparable</strong> phrasal verbs, the app is always <strong>after</strong> the whole construction.",
            "examples": [
                {
                    "en": "Look after your dog.",
                    "ua": "Take care of your by a dog."
                },
                {
                    "en": "She got over the illness.",
                    "ua": "She got over the illness."
                },
                {
                    "en": "I came across an old photo.",
                    "ua": "I came across an old photo."
                },
                {
                    "en": "He ran into an old friend.",
                    "ua": "He ran into an old friend second."
                }
            ]
        },
        {
            "label": "Three-word phrasal verbs",
            "color": "sky",
            "description": "Three-word phrasal verbs are <strong>always</strong> inseparable.",
            "examples": [
                {
                    "en": "She can't put up with the noise.",
                    "ua": "She can't put up with the noise."
                },
                {
                    "en": "I'm looking forward to the trip.",
                    "ua": "I'm looking forward to the trip."
                },
                {
                    "en": "We've run out of milk.",
                    "ua": "We've run out of milk."
                }
            ]
        }
    ]
}

{
    "title": "5. Popular phrasal verbs",
    "intro": "Remember which phrasal verbs are separable and which are not:",
    "rows": [
        {
            "en": "turn on/off",
            "ua": "turn on/off",
            "note": "Split"
        },
        {
            "en": "pick up",
            "ua": "pick up, pick up",
            "note": "Distributed"
        },
        {
            "en": "put on",
            "ua": "put on",
            "note": "Distributed"
        },
        {
            "en": "throw away",
            "ua": "",
            "note": "Allocated"
        },
        {
            "en": "look after",
            "ua": "look after",
            "note": "Unallocated"
        },
        {
            "en": "look for",
            "ua": "look for[[[CODX_6]]]Unallocated",
            "note": "Нерозділюване"
        },
        {
            "en": "get over",
            "ua": "recover, overcome",
            "note": "Inseparable"
        }
    ],
    "warning": "📌 If you are not sure - check in the dictionary!"
}

{
    "title": "6. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Pronoun after the participle instead of between.",
            "wrong": "Turn off it.",
            "right": " ✅ <span class="font-mono">Turn it off.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Modal verb + to.",
            "wrong": "She can to swim.",
            "right": "​​​​​​​​ verb."
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Розділення нерозділюваного phrasal verb.",
            "wrong": "Look your dog after.",
            "right": "​​​​ <span class="font-mono">Look after your dog.</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Verb with -s after modal.",
            "wrong": "He must calls.",
            "right": "​​​​ <span class="font-mono">He must call.</span>"
        }
    ]
}

{
    "title": "7. Brief synopsis",
    "items": [
        "Auxiliaries (be, do, have): <strong>S + Aux + V + O</strong>.",
        "Modals: <strong>S + Modal + Base Verb + O</strong> (without to, without -s).",
        "Separable phrasal verbs: the attachment can be between or after.",
        "Pronoun in separable: <strong>required</strong> between verb and particle.",
        "Inseparable and 3-word phrasal verbs: addition <strong>after</strong> the whole construction."
    ]
}

{
    "title": "8. Practice",
    "select_title": "Exercise 1. Choose the correct option",
    "select_intro": "Choose sentences with the correct word order.",
    "selects": [
        {
            "label": "a) Turn it off. / b) Turn off it.",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) She can to swim. / b) She can swim.",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) Look after the kids. / b) Look the kids after.",
            "prompt": "Which option is correct?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Exercise 2. Put the pronoun in the correct place",
    "input_intro": "Replace the noun with the pronoun in brackets.",
    "inputs": [
        {
            "before": " Pick up the book. (it)",
            "after": "→"
        },
        {
            "before": "Turn off the TV. (it)",
            "after": "→"
        },
        {
            "before": "Put on your shoes. (them)",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Correct the error",
    "rephrase_intro": "Find and correct the error in the word order.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "She must calls him.",
            "example_target": "She must call him."
        },
        {
            "original": "1. He can to play guitar.",
            "placeholder": "Correct word order"
        },
        {
            "original": "2. Throw them. circumstances",
            "placeholder": "Виправ порядок слів"
        }
    ]
}

{
    "title": "Інші сторінки з базової граматики",
    "items": [
        {
            "label": "Basic Word Order — Порядок слів у ствердженні",
            "current": false
        },
        {
            "label": "Word Order in Questions and Negatives — Питання та заперечення",
            "current": false
        },
        {
            "label": "Word Order with Adverbs — Прислівники та обставини",
            "current": false
        },
        {
            "label": "Word Order with Verbs and Objects - Verbs and affixes (current)",
            "current": true
        },
        {
            "label": "Advanced Word Order - Inversion and strengthening",
            "current": false
        }
    ]
}
